xpath.script:
(function() {
    var STORAGE_KEY = 'wl_page_agent_history';

    var TEXT_MAP = {
        '输入新任务，详细描述步骤，回车提交': 'Tulis perintah... (contoh: pesan seblak)',
        '准备就绪': 'Siap',
        '等待任务开始...': 'Menunggu tugas...',
        '正在思考...': 'Sedang berpikir...',
        '正在执行...': 'Sedang menjalankan...',
        '任务完成': 'Tugas selesai',
        '任务已停止': 'Tugas dihentikan',
        '出现错误': 'Terjadi kesalahan',
    };

    function applyStyles() {
        // Background: dark red gradient
        var bg = document.querySelector('[class*="_background_1tu05_"]');
        if (bg) {
            bg.style.cssText += ';background:linear-gradient(135deg,rgba(90,8,14,0.97),rgba(122,12,20,0.97))!important;border-radius:12px!important;box-shadow:0 8px 32px rgba(90,8,14,0.3)!important;';
        }
        // History section
        var hist = document.querySelector('[class*="_historySectionWrapper_1tu05_"]');
        if (hist) hist.style.cssText += ';background:rgba(90,8,14,0.85)!important;';
        // Header
        var header = document.querySelector('[class*="_header_1tu05_"]');
        if (header) header.style.cssText += ';background:rgba(90,8,14,0.6)!important;';
        // Status text: gold
        var st = document.querySelector('[class*="_statusText_1tu05_"]');
        if (st) st.style.cssText += ';color:#f5c400!important;font-weight:600!important;';
        // Indicator: gold
        var ind = document.querySelector('[class*="_indicator_1tu05_"]');
        if (ind) ind.style.cssText += ';background:#f5c400!important;';
        // Input section: cream
        var isw = document.querySelector('[class*="_inputSectionWrapper_1tu05_"]');
        if (isw) isw.style.cssText += ';background:rgba(253,251,245,0.95)!important;';
        // Input field
        var input = document.querySelector('[class*="_taskInput_1tu05_"]');
        if (input) {
            input.style.cssText += ';background:#fff!important;color:#1f1f1f!important;border:1px solid #ddd!important;border-radius:8px!important;font-size:13px!important;padding:8px 12px!important;font-family:Inter,-apple-system,sans-serif!important;';
            // Fix placeholder
            if (input.placeholder && /[\u4e00-\u9fff]/.test(input.placeholder)) {
                input.placeholder = 'Tulis perintah... (contoh: pesan seblak)';
            }
        }
        // Control buttons: gold tint
        document.querySelectorAll('[class*="_controlButton_1tu05_"]').forEach(function(b) {
            if (!b.className.includes('_stopButton_')) {
                b.style.cssText += ';background:rgba(245,196,0,0.15)!important;color:#f5c400!important;border-radius:6px!important;';
            }
        });
    }

    function fixText() {
        // Fix placeholder
        var input = document.querySelector('[class*="_taskInput_1tu05_"]');
        if (input && input.placeholder && /[\u4e00-\u9fff]/.test(input.placeholder)) {
            input.placeholder = 'Tulis perintah... (contoh: pesan seblak)';
        }
        // Fix all Chinese text in agent widget
        var wrapper = document.querySelector('[class*="_wrapper_1tu05_"]');
        if (!wrapper) return;
        var walker = document.createTreeWalker(wrapper, NodeFilter.SHOW_TEXT, null);
        var node;
        while (node = walker.nextNode()) {
            var t = node.textContent;
            for (var cn in TEXT_MAP) {
                if (t.indexOf(cn) >= 0) {
                    node.textContent = t.replace(new RegExp(cn, 'g'), TEXT_MAP[cn]);
                    t = node.textContent;
                }
            }
            // Regex fallback: replace any remaining CJK chars
            if (/[\u4e00-\u9fff]/.test(t)) {
                node.textContent = t.replace(/[\u4e00-\u9fff]+[，。…？！]/g, '');
            }
        }
    }

    function setupAgent() {
        var pa = window.pageAgent;
        if (!pa || pa.disposed) return false;
        try {
            pa.config.language = 'id-ID';
            if (pa.config.pageController && pa.config.pageController.config) {
                pa.config.pageController.config.language = 'id-ID';
            }
        } catch(e) {}
        // Restore history
        try {
            var saved = sessionStorage.getItem(STORAGE_KEY);
            if (saved) {
                var h = JSON.parse(saved);
                if (Array.isArray(h) && h.length > 0) pa.history = h;
            }
        } catch(e) {}
        // Save on message
        try {
            pa.addEventListener('message', function() {
                try { if (pa.history && pa.history.length > 0) sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history)); } catch(e) {}
            });
        } catch(e) {}
        window.addEventListener('beforeunload', function() {
            try { if (pa.history && pa.history.length > 0) sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history)); } catch(e) {}
        });
        return true;
    }

    // Main loop: apply styles + fix text until agent is stable
    var attempts = 0;
    var interval = setInterval(function() {
        attempts++;
        applyStyles();
        fixText();
        if (window.pageAgent && !window.pageAgent.disposed) {
            setupAgent();
        }
        if (attempts >= 60) { // 30 seconds
            clearInterval(interval);
            console.log('[Page Agent] Warung Lakku AI ready (styled, Indonesian, persisted)');
        }
    }, 500);

    // MutationObserver: re-apply on DOM changes
    var observer = new MutationObserver(function() {
        applyStyles();
        fixText();
    });
    if (document.body) {
        observer.observe(document.body, { childList: true, subtree: true, characterData: true });
    }
    setTimeout(function() { observer.disconnect(); }, 30000);
})();
